+/// A JSX attribute on an opening element.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case", tag = "type")]
+pub enum JsxAttribute {
+    /// `name="value"` or `name={expr}`.
+    Named {
+        name: String,
