+/// Result of parsing a JSX source fragment.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct JsxParseResult {
+    pub node: JsxNode,
+    pub diagnostics: Vec<JsxDiagnostic>,
+    pub feature_families_used: Vec<JsxFeatureFamily>,
+}
